#!/usr/bin/env python3
"""
Self-contained Gladiator NN UCI engine — no database file required.

Bot:         9a9734a2-0359-430d-a3c2-e089aeb0d9fd
Generation:  30265
Best streak: 8 consecutive wins
Engine:      Neural network (GPU/CPU)

Requirements
------------
  1. Clone the Gladiator repo
  2. cd into it and run: python install.py
  3. Point Nibbler (or any UCI GUI) at this script
"""

from __future__ import annotations

import sys
import threading

import chess

_PARAMS_JSON = '{"bot_id": "9a9734a2-0359-430d-a3c2-e089aeb0d9fd", "generation": 30265, "parent_id": null, "mutation_scale": 0.02, "search_depth": 1, "weights_b64": ""}'
_BOT_NAME = "Gladiator-NN streak8 gen=30265 id=9a9734a2"


def _pick_device():
    import torch
    if torch.cuda.is_available():
        return torch.device("cuda")
    try:
        import torch_directml
        return torch_directml.device()
    except ImportError:
        pass
    return torch.device("cpu")


def _load_bot(device):
    from gladiator_nn.bot.bot import NNBot, NNBotParams
    return NNBot(NNBotParams.from_json(_PARAMS_JSON), device)


def _parse_position(tokens):
    board = chess.Board()
    idx = 1
    if idx >= len(tokens):
        return board
    if tokens[idx] == "startpos":
        idx += 1
    elif tokens[idx] == "fen":
        idx += 1
        fen_parts = []
        while idx < len(tokens) and tokens[idx] != "moves":
            fen_parts.append(tokens[idx])
            idx += 1
        board = chess.Board(" ".join(fen_parts))
    if idx < len(tokens) and tokens[idx] == "moves":
        idx += 1
        for uci_move in tokens[idx:]:
            board.push_uci(uci_move)
    return board


class _Engine:
    def __init__(self):
        device = _pick_device()
        self._bot = _load_bot(device)
        self._board = chess.Board()
        self._thread = None
        self._stop = threading.Event()

    def run(self):
        for raw in sys.stdin:
            line = raw.strip()
            if not line:
                continue
            tokens = line.split()
            cmd = tokens[0]
            if cmd == "uci":
                print(f"id name {_BOT_NAME}", flush=True)
                print("id author Gladiator", flush=True)
                print("uciok", flush=True)
            elif cmd == "isready":
                print("readyok", flush=True)
            elif cmd == "ucinewgame":
                self._board = chess.Board()
            elif cmd == "position":
                self._board = _parse_position(tokens)
            elif cmd == "go":
                depth = 5
                if "depth" in tokens:
                    try:
                        depth = int(tokens[tokens.index("depth") + 1])
                    except (IndexError, ValueError):
                        pass
                self._stop.clear()
                self._thread = threading.Thread(
                    target=self._search, args=(self._board.copy(), depth), daemon=True
                )
                self._thread.start()
            elif cmd == "stop":
                self._stop.set()
                if self._thread:
                    self._thread.join()
            elif cmd == "quit":
                self._stop.set()
                if self._thread:
                    self._thread.join()
                break

    def _search(self, board, depth):
        move = self._bot.choose_move(board)
        print(f"info depth {depth}", flush=True)
        print(f"bestmove {move.uci()}", flush=True)


if __name__ == "__main__":
    _Engine().run()
